using System.ComponentModel.DataAnnotations;
using System.ComponentModel.DataAnnotations.Schema;

namespace VetClinic.Data;

public class Owner
{
    public int Id { get; set; }

    [Required, MaxLength(100)]
    public string FirstName { get; set; } = "";

    [Required, MaxLength(100)]
    public string LastName { get; set; } = "";

    [Required, MaxLength(200)]
    public string Email { get; set; } = "";

    [Required, MaxLength(20)]
    public string Phone { get; set; } = "";

    [MaxLength(300)]
    public string? Address { get; set; }

    public string FullName => $"{FirstName} {LastName}";

    public List<Patient> Patients { get; set; } = [];
}

public class Patient
{
    public int Id { get; set; }

    [Required, MaxLength(100)]
    public string Name { get; set; } = "";

    [Required, MaxLength(50)]
    public string Species { get; set; } = "";

    [MaxLength(50)]
    public string? Breed { get; set; }

    public DateOnly? DateOfBirth { get; set; }

    [MaxLength(20)]
    public string? Sex { get; set; }

    public double? WeightKg { get; set; }

    [MaxLength(50)]
    public string? MicrochipId { get; set; }

    public int OwnerId { get; set; }
    public Owner Owner { get; set; } = null!;

    public List<TreatmentNote> TreatmentNotes { get; set; } = [];
    public List<Appointment> Appointments { get; set; } = [];
    public List<Invoice> Invoices { get; set; } = [];
}

public class TreatmentNote
{
    public int Id { get; set; }

    public DateTime Date { get; set; } = DateTime.UtcNow;

    [Required, MaxLength(200)]
    public string Title { get; set; } = "";

    [Required]
    public string Description { get; set; } = "";

    [MaxLength(500)]
    public string? Medications { get; set; }

    [MaxLength(100)]
    public string? RecordedBy { get; set; }

    public int PatientId { get; set; }
    public Patient Patient { get; set; } = null!;
}

public class Appointment
{
    public int Id { get; set; }

    public int PatientId { get; set; }
    public Patient Patient { get; set; } = null!;

    public DateTime StartTime { get; set; }
    public DateTime EndTime { get; set; }

    [Required, MaxLength(200)]
    public string Reason { get; set; } = "";

    [MaxLength(500)]
    public string? Notes { get; set; }

    public AppointmentStatus Status { get; set; } = AppointmentStatus.Scheduled;

    [MaxLength(100)]
    public string? Veterinarian { get; set; }
}

public enum AppointmentStatus
{
    Scheduled,
    Completed,
    Cancelled
}

public class Invoice
{
    public int Id { get; set; }

    [MaxLength(20)]
    public string InvoiceNumber { get; set; } = "";

    public int PatientId { get; set; }
    public Patient Patient { get; set; } = null!;

    public DateTime CreatedDate { get; set; } = DateTime.UtcNow;
    public DateTime? DueDate { get; set; }

    public List<InvoiceItem> Items { get; set; } = [];
    public List<Payment> Payments { get; set; } = [];

    [NotMapped]
    public decimal TotalAmount => Items.Sum(i => i.Amount);

    [NotMapped]
    public decimal TotalPaid => Payments.Where(p => p.Status == PaymentStatus.Completed).Sum(p => p.Amount);

    [NotMapped]
    public decimal BalanceDue => TotalAmount - TotalPaid;

    [NotMapped]
    public InvoiceStatus Status =>
        BalanceDue <= 0 && Items.Count > 0 ? InvoiceStatus.Paid :
        TotalPaid > 0 ? InvoiceStatus.PartiallyPaid :
        InvoiceStatus.Unpaid;
}

public class InvoiceItem
{
    public int Id { get; set; }

    [Required, MaxLength(200)]
    public string Description { get; set; } = "";

    public int Quantity { get; set; } = 1;

    [Column(TypeName = "decimal(10,2)")]
    public decimal UnitPrice { get; set; }

    [NotMapped]
    public decimal Amount => Quantity * UnitPrice;

    public int InvoiceId { get; set; }
    public Invoice Invoice { get; set; } = null!;
}

public class Payment
{
    public int Id { get; set; }

    public int InvoiceId { get; set; }
    public Invoice Invoice { get; set; } = null!;

    public DateTime PaymentDate { get; set; } = DateTime.UtcNow;

    [Column(TypeName = "decimal(10,2)")]
    public decimal Amount { get; set; }

    [Required, MaxLength(50)]
    public string Method { get; set; } = "Cash";

    [MaxLength(100)]
    public string? Reference { get; set; }

    public PaymentStatus Status { get; set; } = PaymentStatus.Completed;
}

public enum InvoiceStatus
{
    Unpaid,
    PartiallyPaid,
    Paid
}

public enum PaymentStatus
{
    Completed,
    Refunded
}

