using Microsoft.EntityFrameworkCore;

namespace VetClinic.Data;

public class ClinicService(IDbContextFactory<ApplicationDbContext> factory)
{
    // ── Owners ──────────────────────────────────────────────
    public async Task<List<Owner>> GetOwnersAsync(string? search = null)
    {
        await using var db = await factory.CreateDbContextAsync();
        var q = db.Owners.AsQueryable();
        if (!string.IsNullOrWhiteSpace(search))
            q = q.Where(o => (o.FirstName + " " + o.LastName).Contains(search) || o.Email.Contains(search));
        return await q.OrderBy(o => o.LastName).ToListAsync();
    }

    public async Task<Owner?> GetOwnerAsync(int id)
    {
        await using var db = await factory.CreateDbContextAsync();
        return await db.Owners.Include(o => o.Patients).FirstOrDefaultAsync(o => o.Id == id);
    }

    public async Task<Owner> SaveOwnerAsync(Owner owner)
    {
        await using var db = await factory.CreateDbContextAsync();
        if (owner.Id == 0) db.Owners.Add(owner);
        else db.Owners.Update(owner);
        await db.SaveChangesAsync();
        return owner;
    }

    // ── Patients ────────────────────────────────────────────
    public async Task<List<Patient>> GetPatientsAsync(string? search = null)
    {
        await using var db = await factory.CreateDbContextAsync();
        var q = db.Patients.Include(p => p.Owner).AsQueryable();
        if (!string.IsNullOrWhiteSpace(search))
            q = q.Where(p => p.Name.Contains(search) || p.Owner.LastName.Contains(search));
        return await q.OrderBy(p => p.Name).ToListAsync();
    }

    public async Task<Patient?> GetPatientAsync(int id)
    {
        await using var db = await factory.CreateDbContextAsync();
        return await db.Patients
            .Include(p => p.Owner)
            .Include(p => p.TreatmentNotes.OrderByDescending(t => t.Date))
            .FirstOrDefaultAsync(p => p.Id == id);
    }

    public async Task<Patient> SavePatientAsync(Patient patient)
    {
        await using var db = await factory.CreateDbContextAsync();
        if (patient.Id == 0) db.Patients.Add(patient);
        else db.Patients.Update(patient);
        await db.SaveChangesAsync();
        return patient;
    }

    public async Task DeletePatientAsync(int id)
    {
        await using var db = await factory.CreateDbContextAsync();
        var p = await db.Patients.FindAsync(id);
        if (p != null) { db.Patients.Remove(p); await db.SaveChangesAsync(); }
    }

    // ── Treatment Notes ─────────────────────────────────────
    public async Task<TreatmentNote> SaveTreatmentNoteAsync(TreatmentNote note)
    {
        await using var db = await factory.CreateDbContextAsync();
        if (note.Id == 0) db.TreatmentNotes.Add(note);
        else db.TreatmentNotes.Update(note);
        await db.SaveChangesAsync();
        return note;
    }

    public async Task DeleteTreatmentNoteAsync(int id)
    {
        await using var db = await factory.CreateDbContextAsync();
        var n = await db.TreatmentNotes.FindAsync(id);
        if (n != null) { db.TreatmentNotes.Remove(n); await db.SaveChangesAsync(); }
    }

    // ── Appointments ────────────────────────────────────────
    public async Task<List<Appointment>> GetAppointmentsAsync(DateTime? from = null, DateTime? to = null, AppointmentStatus? status = null)
    {
        await using var db = await factory.CreateDbContextAsync();
        var q = db.Appointments.Include(a => a.Patient).ThenInclude(p => p.Owner).AsQueryable();
        if (from.HasValue) q = q.Where(a => a.StartTime >= from.Value);
        if (to.HasValue) q = q.Where(a => a.StartTime <= to.Value);
        if (status.HasValue) q = q.Where(a => a.Status == status.Value);
        return await q.OrderBy(a => a.StartTime).ToListAsync();
    }

    public async Task<Appointment?> GetAppointmentAsync(int id)
    {
        await using var db = await factory.CreateDbContextAsync();
        return await db.Appointments.Include(a => a.Patient).ThenInclude(p => p.Owner).FirstOrDefaultAsync(a => a.Id == id);
    }

    public async Task<Appointment> SaveAppointmentAsync(Appointment appt)
    {
        await using var db = await factory.CreateDbContextAsync();
        if (appt.Id == 0) db.Appointments.Add(appt);
        else db.Appointments.Update(appt);
        await db.SaveChangesAsync();
        return appt;
    }

    public async Task CancelAppointmentAsync(int id)
    {
        await using var db = await factory.CreateDbContextAsync();
        var a = await db.Appointments.FindAsync(id);
        if (a != null) { a.Status = AppointmentStatus.Cancelled; await db.SaveChangesAsync(); }
    }

    public async Task<bool> HasConflictAsync(DateTime start, DateTime end, int? excludeId = null)
    {
        await using var db = await factory.CreateDbContextAsync();
        return await db.Appointments
            .Where(a => a.Status != AppointmentStatus.Cancelled)
            .Where(a => excludeId == null || a.Id != excludeId)
            .AnyAsync(a => a.StartTime < end && a.EndTime > start);
    }

    public async Task<List<(DateTime Start, DateTime End)>> GetAvailableSlotsAsync(DateOnly date)
    {
        await using var db = await factory.CreateDbContextAsync();
        var dayStart = date.ToDateTime(new TimeOnly(8, 0));
        var dayEnd = date.ToDateTime(new TimeOnly(18, 0));

        var booked = await db.Appointments
            .Where(a => a.Status != AppointmentStatus.Cancelled)
            .Where(a => a.StartTime >= dayStart && a.StartTime < dayEnd)
            .OrderBy(a => a.StartTime)
            .Select(a => new { a.StartTime, a.EndTime })
            .ToListAsync();

        var slots = new List<(DateTime, DateTime)>();
        var cursor = dayStart;
        foreach (var b in booked)
        {
            if (cursor < b.StartTime)
                slots.Add((cursor, b.StartTime));
            if (b.EndTime > cursor) cursor = b.EndTime;
        }
        if (cursor < dayEnd) slots.Add((cursor, dayEnd));
        return slots;
    }

    // ── Invoices ────────────────────────────────────────────
    public async Task<List<Invoice>> GetInvoicesAsync(string? search = null, InvoiceStatus? status = null)
    {
        await using var db = await factory.CreateDbContextAsync();
        var q = db.Invoices
            .Include(i => i.Patient).ThenInclude(p => p.Owner)
            .Include(i => i.Items)
            .Include(i => i.Payments)
            .AsQueryable();
        if (!string.IsNullOrWhiteSpace(search))
            q = q.Where(i => i.InvoiceNumber.Contains(search) || i.Patient.Name.Contains(search));
        var list = await q.OrderByDescending(i => i.CreatedDate).ToListAsync();
        if (status.HasValue)
            list = list.Where(i => i.Status == status.Value).ToList();
        return list;
    }

    public async Task<Invoice?> GetInvoiceAsync(int id)
    {
        await using var db = await factory.CreateDbContextAsync();
        return await db.Invoices
            .Include(i => i.Patient).ThenInclude(p => p.Owner)
            .Include(i => i.Items)
            .Include(i => i.Payments)
            .FirstOrDefaultAsync(i => i.Id == id);
    }

    public async Task<Invoice> SaveInvoiceAsync(Invoice invoice)
    {
        await using var db = await factory.CreateDbContextAsync();
        if (invoice.Id == 0)
        {
            var count = await db.Invoices.CountAsync();
            invoice.InvoiceNumber = $"INV-{count + 1:D5}";
            db.Invoices.Add(invoice);
        }
        else
        {
            db.Invoices.Update(invoice);
        }
        await db.SaveChangesAsync();
        return invoice;
    }

    public async Task AddInvoiceItemAsync(InvoiceItem item)
    {
        await using var db = await factory.CreateDbContextAsync();
        db.InvoiceItems.Add(item);
        await db.SaveChangesAsync();
    }

    public async Task RemoveInvoiceItemAsync(int id)
    {
        await using var db = await factory.CreateDbContextAsync();
        var item = await db.InvoiceItems.FindAsync(id);
        if (item != null) { db.InvoiceItems.Remove(item); await db.SaveChangesAsync(); }
    }

    // ── Payments ────────────────────────────────────────────
    public async Task<Payment> SavePaymentAsync(Payment payment)
    {
        await using var db = await factory.CreateDbContextAsync();
        if (payment.Id == 0) db.Payments.Add(payment);
        else db.Payments.Update(payment);
        await db.SaveChangesAsync();
        return payment;
    }

    public async Task<List<Payment>> GetPaymentHistoryAsync()
    {
        await using var db = await factory.CreateDbContextAsync();
        return await db.Payments
            .Include(p => p.Invoice).ThenInclude(i => i.Patient).ThenInclude(p => p.Owner)
            .OrderByDescending(p => p.PaymentDate)
            .ToListAsync();
    }

    // ── Dashboard stats ─────────────────────────────────────
    public async Task<DashboardStats> GetDashboardStatsAsync()
    {
        await using var db = await factory.CreateDbContextAsync();
        var today = DateTime.UtcNow.Date;
        var tomorrow = today.AddDays(1);
        return new DashboardStats
        {
            TotalPatients = await db.Patients.CountAsync(),
            TotalOwners = await db.Owners.CountAsync(),
            TodayAppointments = await db.Appointments.CountAsync(a => a.StartTime >= today && a.StartTime < tomorrow && a.Status == AppointmentStatus.Scheduled),
            PendingInvoices = await db.Invoices.Include(i => i.Items).Include(i => i.Payments).CountAsync(i => i.Payments.Sum(p => p.Amount) < i.Items.Sum(it => it.Quantity * it.UnitPrice)),
        };
    }
}

public class DashboardStats
{
    public int TotalPatients { get; set; }
    public int TotalOwners { get; set; }
    public int TodayAppointments { get; set; }
    public int PendingInvoices { get; set; }
}

