@page "/patients"
@attribute [Authorize]
@rendermode InteractiveServer
@inject ClinicService Svc
@inject NavigationManager Nav

<PageTitle>Patients</PageTitle>

<div class="d-flex justify-content-between align-items-center mb-3">
    <h1>🐾 Patients</h1>
    <a href="patients/new" class="btn btn-primary">+ Register Patient</a>
</div>

<div class="row mb-3">
    <div class="col-md-4">
        <input type="text" class="form-control" placeholder="Search by name or owner..."
               @bind="searchTerm" @bind:event="oninput" @bind:after="SearchAsync" />
    </div>
</div>

@if (patients is null)
{
    <p><em>Loading...</em></p>
}
else if (patients.Count == 0)
{
    <div class="alert alert-info">No patients found. <a href="patients/new">Register one</a>.</div>
}
else
{
    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Name</th>
                <th>Species</th>
                <th>Breed</th>
                <th>Owner</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var p in patients)
            {
                <tr>
                    <td>@p.Name</td>
                    <td>@p.Species</td>
                    <td>@p.Breed</td>
                    <td>@p.Owner.FullName</td>
                    <td>
                        <a href="patients/@p.Id" class="btn btn-sm btn-outline-primary me-1">Edit</a>
                        <a href="patients/@p.Id/history" class="btn btn-sm btn-outline-secondary me-1">History</a>
                        <button class="btn btn-sm btn-outline-danger" @onclick="() => DeleteAsync(p.Id)">Delete</button>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    List<Patient>? patients;
    string? searchTerm;

    protected override async Task OnInitializedAsync() => patients = await Svc.GetPatientsAsync();

    async Task SearchAsync() => patients = await Svc.GetPatientsAsync(searchTerm);

    async Task DeleteAsync(int id)
    {
        await Svc.DeletePatientAsync(id);
        patients = await Svc.GetPatientsAsync(searchTerm);
    }
}

@page "/patients/new"
@page "/patients/{Id:int}"
@attribute [Authorize]
@rendermode InteractiveServer
@inject ClinicService Svc
@inject NavigationManager Nav

<PageTitle>@(Id == null ? "Register Patient" : "Edit Patient")</PageTitle>

<h1>@(Id == null ? "Register Patient" : "Edit Patient")</h1>

@if (!string.IsNullOrEmpty(error))
{
    <div class="alert alert-danger">@error</div>
}

<div class="row">
    <div class="col-md-6">
        <EditForm Model="patient" OnValidSubmit="SaveAsync" FormName="PatientForm">
            <DataAnnotationsValidator />
            <ValidationSummary />

            <fieldset class="border p-3 mb-3">
                <legend class="w-auto px-2">Owner Information</legend>

                @if (Id == null)
                {
                    <div class="mb-2">
                        <label class="form-label">Existing Owner</label>
                        <select class="form-select" @onchange="OwnerSelected">
                            <option value="">— New Owner —</option>
                            @if (owners != null)
                            {
                                @foreach (var o in owners)
                                {
                                    <option value="@o.Id">@o.FullName (@o.Email)</option>
                                }
                            }
                        </select>
                    </div>
                }

                @if (!useExistingOwner)
                {
                    <div class="row mb-2">
                        <div class="col">
                            <label class="form-label">First Name</label>
                            <InputText class="form-control" @bind-Value="owner.FirstName" />
                        </div>
                        <div class="col">
                            <label class="form-label">Last Name</label>
                            <InputText class="form-control" @bind-Value="owner.LastName" />
                        </div>
                    </div>
                    <div class="row mb-2">
                        <div class="col">
                            <label class="form-label">Email</label>
                            <InputText class="form-control" @bind-Value="owner.Email" />
                        </div>
                        <div class="col">
                            <label class="form-label">Phone</label>
                            <InputText class="form-control" @bind-Value="owner.Phone" />
                        </div>
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Address</label>
                        <InputText class="form-control" @bind-Value="owner.Address" />
                    </div>
                }
            </fieldset>

            <fieldset class="border p-3 mb-3">
                <legend class="w-auto px-2">Pet Information</legend>

                <div class="row mb-2">
                    <div class="col">
                        <label class="form-label">Pet Name *</label>
                        <InputText class="form-control" @bind-Value="patient.Name" />
                    </div>
                    <div class="col">
                        <label class="form-label">Species *</label>
                        <InputSelect class="form-select" @bind-Value="patient.Species">
