@code {
    List<Appointment>? appointments;
    List<(DateTime Start, DateTime End)>? availableSlots;
    DateOnly selectedDate = DateOnly.FromDateTime(DateTime.Today);
    string? statusFilter;
    bool showSlots;

    protected override async Task OnInitializedAsync() => await LoadAsync();

    async Task LoadAsync()
    {
        showSlots = false;
        AppointmentStatus? status = Enum.TryParse<AppointmentStatus>(statusFilter, out var s) ? s : null;
        var from = selectedDate.ToDateTime(TimeOnly.MinValue);
        var to = selectedDate.ToDateTime(TimeOnly.MaxValue);
        appointments = await Svc.GetAppointmentsAsync(from, to, status);
    }

    async Task ShowAvailability()
    {
        availableSlots = await Svc.GetAvailableSlotsAsync(selectedDate);
        showSlots = true;
    }

    async Task CancelAsync(int id)
    {
        await Svc.CancelAppointmentAsync(id);
        await LoadAsync();
    }

    async Task CompleteAsync(Appointment a)
    {
        a.Status = AppointmentStatus.Completed;
        a.Patient = null!;
        await Svc.SaveAppointmentAsync(a);
        await LoadAsync();
    }

    string StatusBadge(AppointmentStatus s) => s switch
    {
        AppointmentStatus.Scheduled => "bg-primary",
        AppointmentStatus.Completed => "bg-success",
        AppointmentStatus.Cancelled => "bg-secondary",
        _ => "bg-dark"
    };
}

