</div>

@code {
    [Parameter] public int? Id { get; set; }

    Appointment appt = new() { StartTime = DateTime.Today.AddHours(9), EndTime = DateTime.Today.AddHours(9).AddMinutes(30) };
    List<Patient>? patients;
    List<(DateTime Start, DateTime End)>? availableSlots;
    int durationMinutes = 30;
    bool hasConflict;
    bool saving;
    string? error;
    string? success;

    protected override async Task OnInitializedAsync()
    {
        patients = await Svc.GetPatientsAsync();

        if (Id.HasValue)
        {
            var existing = await Svc.GetAppointmentAsync(Id.Value);
            if (existing is null) { Nav.NavigateTo("appointments"); return; }
            appt = existing;
            appt.Patient = null!;
            durationMinutes = (int)(appt.EndTime - appt.StartTime).TotalMinutes;
        }

        await LoadSlots();
    }

    async Task CheckAvailability()
    {
        UpdateEndTime();
        hasConflict = await Svc.HasConflictAsync(appt.StartTime, appt.EndTime, Id);
        await LoadSlots();
    }

    void UpdateEndTime()
    {
        appt.EndTime = appt.StartTime.AddMinutes(durationMinutes);
    }

    async Task LoadSlots()
    {
        availableSlots = await Svc.GetAvailableSlotsAsync(DateOnly.FromDateTime(appt.StartTime));
    }

    void SelectSlot(DateTime start)
    {
        appt.StartTime = start;
        UpdateEndTime();
    }

    async Task SaveAsync()
    {
        saving = true;
        error = null;
        success = null;

        if (appt.PatientId == 0) { error = "Please select a patient."; saving = false; return; }

        hasConflict = await Svc.HasConflictAsync(appt.StartTime, appt.EndTime, Id);
        if (hasConflict) { error = "Time slot conflicts with another appointment."; saving = false; return; }

        try
        {
            await Svc.SaveAppointmentAsync(appt);
            Nav.NavigateTo("appointments");
        }
        catch (Exception ex)
        {
            error = ex.InnerException?.Message ?? ex.Message;
            saving = false;
        }
    }
}

