                            <td>@item.UnitPrice.ToString("C")</td>
                            <td>@item.Amount.ToString("C")</td>
                            <td><button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveItemAsync(item.Id)">✕</button></td>
                        </tr>
                    }
                    <tr class="table-active">
                        <td>
                            <input class="form-control form-control-sm" placeholder="Description" @bind="newItem.Description" />
                        </td>
                        <td style="width:80px">
                            <input type="number" class="form-control form-control-sm" @bind="newItem.Quantity" min="1" />
                        </td>
                        <td style="width:120px">
                            <input type="number" class="form-control form-control-sm" @bind="newItem.UnitPrice" min="0" step="0.01" />
                        </td>
                        <td>@((newItem.Quantity * newItem.UnitPrice).ToString("C"))</td>
                        <td><button class="btn btn-sm btn-success" @onclick="AddItemAsync">+</button></td>
                    </tr>
                </tbody>
                <tfoot>
                    <tr class="fw-bold">
                        <td colspan="3" class="text-end">Total:</td>
                        <td>@invoice.TotalAmount.ToString("C")</td>
                        <td></td>
                    </tr>
                    <tr>
                        <td colspan="3" class="text-end">Paid:</td>
                        <td>@invoice.TotalPaid.ToString("C")</td>
                        <td></td>
                    </tr>
                    <tr class="fw-bold text-danger">
                        <td colspan="3" class="text-end">Balance Due:</td>
                        <td>@invoice.BalanceDue.ToString("C")</td>
                        <td></td>
                    </tr>
                </tfoot>
            </table>

            @if (invoice.BalanceDue > 0)
            {
                <h4 class="mt-4">Process Payment</h4>
                <div class="card">
                    <div class="card-body">
                        <div class="row">
                            <div class="col-md-3">
                                <label class="form-label">Amount</label>
                                <input type="number" class="form-control" @bind="payment.Amount" min="0.01" step="0.01" />
                            </div>
                            <div class="col-md-3">
                                <label class="form-label">Method</label>
                                <select class="form-select" @bind="payment.Method">
                                    <option value="Cash">Cash</option>
                                    <option value="Credit Card">Credit Card</option>
                                    <option value="Debit Card">Debit Card</option>
                                    <option value="Check">Check</option>
                                    <option value="Bank Transfer">Bank Transfer</option>
                                </select>
                            </div>
                            <div class="col-md-3">
                                <label class="form-label">Reference</label>
                                <input type="text" class="form-control" @bind="payment.Reference" />
                            </div>
                            <div class="col-md-3 d-flex align-items-end">
                                <button class="btn btn-success w-100" @onclick="ProcessPaymentAsync">
                                    Process Payment
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            }

            @if (invoice.Payments.Count > 0)
            {
                <h4 class="mt-4">Payment History</h4>
                <table class="table table-sm">
                    <thead>
                        <tr><th>Date</th><th>Amount</th><th>Method</th><th>Reference</th><th>Status</th></tr>
                    </thead>
                    <tbody>
                        @foreach (var p in invoice.Payments.OrderByDescending(p => p.PaymentDate))
                        {
                            <tr>
                                <td>@p.PaymentDate.ToString("MMM dd, yyyy h:mm tt")</td>
                                <td>@p.Amount.ToString("C")</td>
                                <td>@p.Method</td>
                                <td>@(p.Reference ?? "—")</td>
                                <td><span class="badge @(p.Status == PaymentStatus.Completed ? "bg-success" : "bg-secondary")">@p.Status</span></td>
                            </tr>
                        }
                    </tbody>
                </table>
            }

            <div class="mt-3">
                <a href="billing" class="btn btn-secondary">← Back to Invoices</a>
            </div>
        }
    </div>
</div>

@code {
    [Parameter] public int? Id { get; set; }

    Invoice? invoice = new();
    List<Patient>? patients;
    InvoiceItem newItem = new() { Quantity = 1 };
    Payment payment = new();
    DateOnly? dueDate;
    string? error;

    protected override async Task OnInitializedAsync()
    {
        patients = await Svc.GetPatientsAsync();

        if (Id.HasValue)
        {
            invoice = await Svc.GetInvoiceAsync(Id.Value);
            if (invoice is null) Nav.NavigateTo("billing");
            else payment.Amount = invoice.BalanceDue;
        }
    }

    async Task CreateAsync()
    {
        if (invoice!.PatientId == 0) { error = "Select a patient."; return; }
        invoice.DueDate = dueDate?.ToDateTime(TimeOnly.MinValue);
        try
        {
            var saved = await Svc.SaveInvoiceAsync(invoice);
            Nav.NavigateTo($"billing/{saved.Id}");
        }
        catch (Exception ex) { error = ex.InnerException?.Message ?? ex.Message; }
    }

    async Task AddItemAsync()
    {
        if (string.IsNullOrWhiteSpace(newItem.Description)) return;
        newItem.InvoiceId = invoice!.Id;
        await Svc.AddInvoiceItemAsync(newItem);
        newItem = new InvoiceItem { Quantity = 1 };
        invoice = await Svc.GetInvoiceAsync(Id!.Value);
    }

    async Task RemoveItemAsync(int itemId)
    {
        await Svc.RemoveInvoiceItemAsync(itemId);
        invoice = await Svc.GetInvoiceAsync(Id!.Value);
    }

    async Task ProcessPaymentAsync()
    {
        if (payment.Amount <= 0) { error = "Enter a valid amount."; return; }
        payment.InvoiceId = invoice!.Id;
        payment.PaymentDate = DateTime.UtcNow;
        await Svc.SavePaymentAsync(payment);
        invoice = await Svc.GetInvoiceAsync(Id!.Value);
        payment = new Payment { Amount = invoice!.BalanceDue };
        error = null;
    }

    string StatusBadge(InvoiceStatus s) => s switch
    {
        InvoiceStatus.Unpaid => "bg-danger",
        InvoiceStatus.PartiallyPaid => "bg-warning text-dark",
        InvoiceStatus.Paid => "bg-success",
        _ => "bg-dark"
    };
}

