@code {
    [Parameter] public int? Id { get; set; }

    Patient patient = new();
    Owner owner = new();
    List<Owner>? owners;
    bool useExistingOwner;
    bool saving;
    string? error;

    protected override async Task OnInitializedAsync()
    {
        owners = await Svc.GetOwnersAsync();

        if (Id.HasValue)
        {
            var existing = await Svc.GetPatientAsync(Id.Value);
            if (existing is null) { Nav.NavigateTo("patients"); return; }
            patient = existing;
            owner = existing.Owner;
            useExistingOwner = true;
        }
    }

    void OwnerSelected(ChangeEventArgs e)
    {
        if (int.TryParse(e.Value?.ToString(), out var oid))
        {
            var selected = owners?.FirstOrDefault(o => o.Id == oid);
            if (selected != null) { owner = selected; useExistingOwner = true; return; }
        }
        owner = new Owner();
        useExistingOwner = false;
    }

    async Task SaveAsync()
    {
        saving = true;
        error = null;
        try
        {
            if (!useExistingOwner || owner.Id == 0)
                owner = await Svc.SaveOwnerAsync(owner);

            patient.OwnerId = owner.Id;
            patient.Owner = null!;
            await Svc.SavePatientAsync(patient);
            Nav.NavigateTo("patients");
        }
        catch (Exception ex)
        {
            error = ex.InnerException?.Message ?? ex.Message;
            saving = false;
        }
    }
}

