{"file_text": "@page "/patients/{Id:int}/history"
@attribute [Authorize]
@rendermode InteractiveServer
@inject ClinicService Svc
@inject NavigationManager Nav
@using Microsoft.AspNetCore.Components.Authorization

<PageTitle>Medical History — @(patient?.Name ?? "Patient")</PageTitle>

@if (patient is null)
{
    <p><em>Loading...</em></p>
}
else
{
    <div class="d-flex justify-content-between align-items-center mb-3">
        <h1>📋 Medical History — @patient.Name</h1>
        <a href="patients/@Id" class="btn btn-outline-secondary">← Back to Patient</a>
    </div>

    <div class="row mb-4">
        <div class="col-md-4">
            <div class="card">
                <div class="card-body">
                    <p><strong>Species:</strong> @patient.Species</p>
                    <p><strong>Breed:</strong> @(patient.Breed ?? "N/A")</p>
                    <p><strong>DOB:</strong> @(patient.DateOfBirth?.ToString("MMM dd, yyyy") ?? "N/A")</p>
                    <p><strong>Weight:</strong> @(patient.WeightKg.HasValue ? $"{patient.WeightKg} kg" : "N/A")</p>
                    <p><strong>Owner:</strong> @patient.Owner.FullName</p>
                </div>
            </div>
        </div>
    </div>

    <h3>Treatment Notes</h3>

    <div class="card mb-3">
        <div class="card-header">
            <h5>@(editingNote?.Id > 0 ? "Edit Note" : "Add Treatment Note")</h5>
        </div>
        <div class="card-body">
            <EditForm Model="editingNote" OnValidSubmit="SaveNoteAsync" FormName="NoteForm">
                <DataAnnotationsValidator />
                <div class="row mb-2">
                    <div class="col-md-4">
                        <label class="form-label">Date</label>
                        <InputDate class="form-control" Type="InputDateType.DateTimeLocal" @bind-Value="editingNote!.Date" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Title *</label>
                        <InputText class="form-control" @bind-Value="editingNote.Title" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Recorded By</label>
                        <InputText class="form-control" @bind-Value="editingNote.RecordedBy" />
                    </div>
                </div>
                <div class="mb-2">
                    <label class="form-label">Description *</label>
                    <InputTextArea class="form-control" rows="3" @bind-Value="editingNote.Description" />
                </div>
                <div class="mb-2">
                    <label class="form-label">Medications</label>
                    <InputText class="form-control" @bind-Value="editingNote.Medications" />
                </div>
                <button type="submit" class="btn btn-primary me-2">Save Note</button>
                @if (editingNote.Id > 0)
                {
                    <button type="button" class="btn btn-secondary" @onclick="CancelEdit">Cancel</button>
                }
            </EditForm>
        </div>
    </div>

    @if (patient.TreatmentNotes.Count == 0)
    {
        <div class="alert alert-info">No treatment notes yet.</div>
    }
    else
    {
        @foreach (var note in patient.TreatmentNotes)
        {
            <div class="card mb-2">
                <div class="card-body">
                    <div class="d-flex justify-content-between">
                        <h5>@note.Title</h5>
                        <small class="text-muted">@note.Date.ToString("MMM dd, yyyy h:mm tt") — @(note.RecordedBy ?? "Staff")</small>
                    </div>
                    <p>@note.Description</p>
                    @if (!string.IsNullOrEmpty(note.Medications))
                    {
                        <p><strong>Medications:</strong> @note.Medications</p>
                    }
                    <button class="btn btn-sm btn-outline-primary me-1" @onclick="() => EditNote(note)">Edit</button>
                    <button class="btn btn-sm btn-outline-danger" @onclick="() => DeleteNoteAsync(note.Id)">Delete</button>
                </div>
            </div>
        }
    }
}

@code {
    [Parameter] public int Id { get; set; }

    Patient? patient;
    TreatmentNote? editingNote;

    protected override async Task OnInitializedAsync()
    {
        await LoadAsync();
        ResetNote();
    }

    async Task LoadAsync()
    {
        patient = await Svc.GetPatientAsync(Id);
        if (patient is null) Nav.NavigateTo("patients");
    }

    void ResetNote()
    {
        editingNote = new TreatmentNote { PatientId = Id, Date = DateTime.UtcNow };
    }

    void EditNote(TreatmentNote note)
    {
        editingNote = new TreatmentNote
        {
            Id = note.Id,
            PatientId = note.PatientId,
            Date = note.Date,
            Title = note.Title,
            Description = note.Description,
            Medications = note.Medications,
            RecordedBy = note.RecordedBy
        };
    }

    void CancelEdit() => ResetNote();

    async Task SaveNoteAsync()
    {
        await Svc.SaveTreatmentNoteAsync(editingNote!);
        await LoadAsync();
        ResetNote();
    }

    async Task DeleteNoteAsync(int id)
    {
        await Svc.DeleteTreatmentNoteAsync(id);
        await LoadAsync();
    }
}
