{"file_text": "@page "/appointments"
@attribute [Authorize]
@rendermode InteractiveServer
@inject ClinicService Svc
@inject NavigationManager Nav

<PageTitle>Appointments</PageTitle>

<div class="d-flex justify-content-between align-items-center mb-3">
    <h1>📅 Appointments</h1>
    <a href="appointments/new" class="btn btn-primary">+ New Appointment</a>
</div>

<div class="row mb-3">
    <div class="col-md-3">
        <label class="form-label">Date</label>
        <input type="date" class="form-control" @bind="selectedDate" @bind:after="LoadAsync" />
    </div>
    <div class="col-md-3">
        <label class="form-label">Status</label>
        <select class="form-select" @bind="statusFilter" @bind:after="LoadAsync">
            <option value="">All</option>
            <option value="Scheduled">Scheduled</option>
            <option value="Completed">Completed</option>
            <option value="Cancelled">Cancelled</option>
        </select>
    </div>
    <div class="col-md-3 d-flex align-items-end">
        <button class="btn btn-outline-secondary" @onclick="ShowAvailability">Show Available Slots</button>
    </div>
</div>

@if (showSlots)
{
    <div class="card mb-3">
        <div class="card-header"><h5>Available Slots for @selectedDate.ToString("MMM dd, yyyy")</h5></div>
        <div class="card-body">
            @if (availableSlots?.Count > 0)
            {
                <div class="d-flex flex-wrap gap-2">
                    @foreach (var slot in availableSlots)
                    {
                        <span class="badge bg-success fs-6 p-2">
                            @slot.Start.ToString("h:mm tt") — @slot.End.ToString("h:mm tt")
                        </span>
                    }
                </div>
            }
            else
            {
                <p class="text-muted">No available slots for this date.</p>
            }
        </div>
    </div>
}

@if (appointments is null)
{
    <p><em>Loading...</em></p>
}
else if (appointments.Count == 0)
{
    <div class="alert alert-info">No appointments found for the selected criteria.</div>
}
else
{
    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Time</th>
                <th>Patient</th>
                <th>Owner</th>
                <th>Reason</th>
                <th>Vet</th>
                <th>Status</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var a in appointments)
            {
                <tr class="@(a.Status == AppointmentStatus.Cancelled ? "table-secondary" : "")">
                    <td>@a.StartTime.ToString("h:mm tt") — @a.EndTime.ToString("h:mm tt")</td>
                    <td>@a.Patient.Name</td>
                    <td>@a.Patient.Owner.FullName</td>
                    <td>@a.Reason</td>
                    <td>@(a.Veterinarian ?? "—")</td>
                    <td>
                        <span class="badge @StatusBadge(a.Status)">@a.Status</span>
                    </td>
                    <td>
                        @if (a.Status == AppointmentStatus.Scheduled)
                        {
                            <a href="appointments/@a.Id" class="btn btn-sm btn-outline-primary me-1">Reschedule</a>
                            <button class="btn btn-sm btn-outline-warning me-1" @onclick="() => CompleteAsync(a)">Complete</button>
                            <button class="btn btn-sm btn-outline-danger" @onclick="() => CancelAsync(a.Id)">Cancel</button>
                        }
                        else
                        {
                            <a href="appointments/@a.Id" class="btn btn-sm btn-outline-secondary">View</a>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    List<Appointment>? appointments;
    List<(DateTime Start, DateTime End)>? availableSlots;
    DateOnly selectedDate = DateOnly.FromDateTime(DateTime.Today);
    string? statusFilter;
    bool showSlots;

    protected override async Task OnInitializedAsync() => await LoadAsync();

    async Task LoadAsync()
    {
        showSlots = false;
        AppointmentStatus? status = Enum.TryParse<AppointmentStatus>(statusFilter, out var s) ? s : null;
        var from = selectedDate.ToDateTime(TimeOnly.MinValue);
        var to = selectedDate.ToDateTime(TimeOnly.MaxValue);
        appointments = await Svc.GetAppointmentsAsync(from, to, status);
    }

    async Task ShowAvailability()
    {
        availableSlots = await Svc.GetAvailableSlotsAsync(selectedDate);
        showSlots = true;
    }

    async Task CancelAsync(int id)
    {
        await Svc.CancelAppointmentAsync(id);
        await LoadAsync();
    }

    async Task CompleteAsync(Appointment a)
    {
        a.Status = AppointmentStatus.Completed;
        a.Patient = null!;
        await Svc.SaveAppointmentAsync(a);
        await LoadAsync();
    }

    string StatusBadge(AppointmentStatus s) => s switch
    {
        AppointmentStatus.Scheduled => "bg-primary",
        AppointmentStatus.Completed => "bg-success",
        AppointmentStatus.Cancelled => "bg-secondary",
        _ => "bg-dark"
    };
}
