{"file_text": "@page "/appointments/new"
@page "/appointments/{Id:int}"
@attribute [Authorize]
@rendermode InteractiveServer
@inject ClinicService Svc
@inject NavigationManager Nav

<PageTitle>@(Id == null ? "New Appointment" : "Edit Appointment")</PageTitle>

<h1>@(Id == null ? "New Appointment" : "Reschedule Appointment")</h1>

@if (!string.IsNullOrEmpty(error))
{
    <div class="alert alert-danger">@error</div>
}

@if (!string.IsNullOrEmpty(success))
{
    <div class="alert alert-success">@success</div>
}

<div class="row">
    <div class="col-md-6">
        <EditForm Model="appt" OnValidSubmit="SaveAsync" FormName="AppointmentForm">
            <DataAnnotationsValidator />
            <ValidationSummary />

            <div class="mb-3">
                <label class="form-label">Patient *</label>
                <InputSelect class="form-select" @bind-Value="appt.PatientId">
                    <option value="0">Select patient...</option>
                    @if (patients != null)
                    {
                        @foreach (var p in patients)
                        {
                            <option value="@p.Id">@p.Name (@p.Owner.FullName)</option>
                        }
                    }
                </InputSelect>
            </div>

            <div class="row mb-3">
                <div class="col">
                    <label class="form-label">Start Time *</label>
                    <InputDate class="form-control" Type="InputDateType.DateTimeLocal"
                               @bind-Value="appt.StartTime" @bind-Value:after="CheckAvailability" />
                </div>
                <div class="col">
                    <label class="form-label">Duration</label>
                    <select class="form-select" @bind="durationMinutes" @onchange="UpdateEndTime">
                        <option value="15">15 min</option>
                        <option value="30">30 min</option>
                        <option value="45">45 min</option>
                        <option value="60">1 hour</option>
                    </select>
                </div>
            </div>

            <div class="mb-3">
                <label class="form-label">End Time</label>
                <InputDate class="form-control" Type="InputDateType.DateTimeLocal" @bind-Value="appt.EndTime" />
            </div>

            @if (hasConflict)
            {
                <div class="alert alert-warning">⚠️ This time slot conflicts with an existing appointment.</div>
            }

            <div class="mb-3">
                <label class="form-label">Reason *</label>
                <InputText class="form-control" @bind-Value="appt.Reason" />
            </div>

            <div class="mb-3">
                <label class="form-label">Veterinarian</label>
                <InputText class="form-control" @bind-Value="appt.Veterinarian" />
            </div>

            <div class="mb-3">
                <label class="form-label">Notes</label>
                <InputTextArea class="form-control" rows="3" @bind-Value="appt.Notes" />
            </div>

            <button type="submit" class="btn btn-primary me-2" disabled="@saving">
                @(saving ? "Saving..." : "Save Appointment")
            </button>
            <a href="appointments" class="btn btn-secondary">Cancel</a>
        </EditForm>
    </div>

    <div class="col-md-6">
        <div class="card">
            <div class="card-header"><h5>Available Slots — @DateOnly.FromDateTime(appt.StartTime).ToString("MMM dd, yyyy")</h5></div>
            <div class="card-body">
                @if (availableSlots?.Count > 0)
                {
                    <div class="d-flex flex-wrap gap-2">
                        @foreach (var slot in availableSlots)
                        {
                            <button class="btn btn-outline-success" @onclick="() => SelectSlot(slot.Start)">
                                @slot.Start.ToString("h:mm tt") — @slot.End.ToString("h:mm tt")
                            </button>
                        }
                    </div>
                }
                else
                {
                    <p class="text-muted">No available slots.</p>
                }
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter] public int? Id { get; set; }

    Appointment appt = new() { StartTime = DateTime.Today.AddHours(9), EndTime = DateTime.Today.AddHours(9).AddMinutes(30) };
    List<Patient>? patients;
    List<(DateTime Start, DateTime End)>? availableSlots;
    int durationMinutes = 30;
    bool hasConflict;
    bool saving;
    string? error;
    string? success;

    protected override async Task OnInitializedAsync()
    {
        patients = await Svc.GetPatientsAsync();

        if (Id.HasValue)
        {
            var existing = await Svc.GetAppointmentAsync(Id.Value);
            if (existing is null) { Nav.NavigateTo("appointments"); return; }
            appt = existing;
            appt.Patient = null!;
            durationMinutes = (int)(appt.EndTime - appt.StartTime).TotalMinutes;
        }

        await LoadSlots();
    }

    async Task CheckAvailability()
    {
        UpdateEndTime();
        hasConflict = await Svc.HasConflictAsync(appt.StartTime, appt.EndTime, Id);
        await LoadSlots();
    }

    void UpdateEndTime()
    {
        appt.EndTime = appt.StartTime.AddMinutes(durationMinutes);
    }

    async Task LoadSlots()
    {
        availableSlots = await Svc.GetAvailableSlotsAsync(DateOnly.FromDateTime(appt.StartTime));
    }

    void SelectSlot(DateTime start)
    {
        appt.StartTime = start;
        UpdateEndTime();
    }

    async Task SaveAsync()
    {
        saving = true;
        error = null;
        success = null;

        if (appt.PatientId == 0) { error = "Please select a patient."; saving = false; return; }

        hasConflict = await Svc.HasConflictAsync(appt.StartTime, appt.EndTime, Id);
        if (hasConflict) { error = "Time slot conflicts with another appointment."; saving = false; return; }

        try
        {
            await Svc.SaveAppointmentAsync(appt);
            Nav.NavigateTo("appointments");
        }
        catch (Exception ex)
        {
            error = ex.InnerException?.Message ?? ex.Message;
            saving = false;
        }
    }
}
