{"file_text": "@page "/billing"
@attribute [Authorize]
@rendermode InteractiveServer
@inject ClinicService Svc
@inject NavigationManager Nav

<PageTitle>Billing</PageTitle>

<div class="d-flex justify-content-between align-items-center mb-3">
    <h1>💰 Invoices</h1>
    <div>
        <a href="billing/new" class="btn btn-primary me-2">+ Create Invoice</a>
        <a href="billing/payments" class="btn btn-outline-secondary">Payment History</a>
    </div>
</div>

<div class="row mb-3">
    <div class="col-md-4">
        <input type="text" class="form-control" placeholder="Search invoices..."
               @bind="searchTerm" @bind:event="oninput" @bind:after="LoadAsync" />
    </div>
    <div class="col-md-3">
        <select class="form-select" @bind="statusFilter" @bind:after="LoadAsync">
            <option value="">All Statuses</option>
            <option value="Unpaid">Unpaid</option>
            <option value="PartiallyPaid">Partially Paid</option>
            <option value="Paid">Paid</option>
        </select>
    </div>
</div>

@if (invoices is null)
{
    <p><em>Loading...</em></p>
}
else if (invoices.Count == 0)
{
    <div class="alert alert-info">No invoices found.</div>
}
else
{
    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Invoice #</th>
                <th>Date</th>
                <th>Patient</th>
                <th>Owner</th>
                <th>Total</th>
                <th>Paid</th>
                <th>Balance</th>
                <th>Status</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var inv in invoices)
            {
                <tr>
                    <td>@inv.InvoiceNumber</td>
                    <td>@inv.CreatedDate.ToString("MMM dd, yyyy")</td>
                    <td>@inv.Patient.Name</td>
                    <td>@inv.Patient.Owner.FullName</td>
                    <td>@inv.TotalAmount.ToString("C")</td>
                    <td>@inv.TotalPaid.ToString("C")</td>
                    <td>@inv.BalanceDue.ToString("C")</td>
                    <td><span class="badge @StatusBadge(inv.Status)">@inv.Status</span></td>
                    <td>
                        <a href="billing/@inv.Id" class="btn btn-sm btn-outline-primary">Details</a>
                    </td>
                </tr>
            }
        </tbody>
