@page "/patients/new"
@page "/patients/{Id:int}"
@attribute [Authorize]
@rendermode InteractiveServer
@inject ClinicService Svc
@inject NavigationManager Nav

<PageTitle>@(Id == null ? "Register Patient" : "Edit Patient")</PageTitle>

<h1>@(Id == null ? "Register Patient" : "Edit Patient")</h1>

@if (!string.IsNullOrEmpty(error))
{
    <div class="alert alert-danger">@error</div>
}

<div class="row">
    <div class="col-md-6">
        <EditForm Model="patient" OnValidSubmit="SaveAsync" FormName="PatientForm">
            <DataAnnotationsValidator />
            <ValidationSummary />

            <fieldset class="border p-3 mb-3">
                <legend class="w-auto px-2">Owner Information</legend>

                @if (Id == null)
                {
                    <div class="mb-2">
                        <label class="form-label">Existing Owner</label>
                        <select class="form-select" @onchange="OwnerSelected">
                            <option value="">— New Owner —</option>
                            @if (owners != null)
                            {
                                @foreach (var o in owners)
                                {
                                    <option value="@o.Id">@o.FullName (@o.Email)</option>
                                }
                            }
                        </select>
                    </div>
                }

                @if (!useExistingOwner)
                {
                    <div class="row mb-2">
                        <div class="col">
                            <label class="form-label">First Name</label>
                            <InputText class="form-control" @bind-Value="owner.FirstName" />
                        </div>
                        <div class="col">
                            <label class="form-label">Last Name</label>
                            <InputText class="form-control" @bind-Value="owner.LastName" />
                        </div>
                    </div>
                    <div class="row mb-2">
                        <div class="col">
                            <label class="form-label">Email</label>
                            <InputText class="form-control" @bind-Value="owner.Email" />
                        </div>
                        <div class="col">
                            <label class="form-label">Phone</label>
                            <InputText class="form-control" @bind-Value="owner.Phone" />
                        </div>
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Address</label>
                        <InputText class="form-control" @bind-Value="owner.Address" />
                    </div>
                }
            </fieldset>

            <fieldset class="border p-3 mb-3">
                <legend class="w-auto px-2">Pet Information</legend>

                <div class="row mb-2">
                    <div class="col">
                        <label class="form-label">Pet Name *</label>
                        <InputText class="form-control" @bind-Value="patient.Name" />
                    </div>
                    <div class="col">
                        <label class="form-label">Species *</label>
                        <InputSelect class="form-select" @bind-Value="patient.Species">
                            <option value="">Select...</option>
                            <option value="Dog">Dog</option>
                            <option value="Cat">Cat</option>
                            <option value="Bird">Bird</option>
                            <option value="Rabbit">Rabbit</option>
                            <option value="Reptile">Reptile</option>
                            <option value="Other">Other</option>
                        </InputSelect>
                    </div>
                </div>
                <div class="row mb-2">
                    <div class="col">
                        <label class="form-label">Breed</label>
                        <InputText class="form-control" @bind-Value="patient.Breed" />
                    </div>
                    <div class="col">
                        <label class="form-label">Sex</label>
                        <InputSelect class="form-select" @bind-Value="patient.Sex">
                            <option value="">Select...</option>
                            <option value="Male">Male</option>
                            <option value="Female">Female</option>
                            <option value="Male (Neutered)">Male (Neutered)</option>
                            <option value="Female (Spayed)">Female (Spayed)</option>
                        </InputSelect>
                    </div>
                </div>
                <div class="row mb-2">
                    <div class="col">
                        <label class="form-label">Date of Birth</label>
                        <InputDate class="form-control" @bind-Value="patient.DateOfBirth" />
                    </div>
                    <div class="col">
                        <label class="form-label">Weight (kg)</label>
                        <InputNumber class="form-control" @bind-Value="patient.WeightKg" />
                    </div>
                </div>
                <div class="mb-2">
                    <label class="form-label">Microchip ID</label>
                    <InputText class="form-control" @bind-Value="patient.MicrochipId" />
                </div>
            </fieldset>

            <button type="submit" class="btn btn-primary me-2" disabled="@saving">
                @(saving ? "Saving..." : "Save")
            </button>
            <a href="patients" class="btn btn-secondary">Cancel</a>
        </EditForm>
    </div>
</div>

@code {
    [Parameter] public int? Id { get; set; }

    Patient patient = new();
    Owner owner = new();
    List<Owner>? owners;
    bool useExistingOwner;
    bool saving;
    string? error;

    protected override async Task OnInitializedAsync()
    {
        owners = await Svc.GetOwnersAsync();

        if (Id.HasValue)
        {
            var existing = await Svc.GetPatientAsync(Id.Value);
            if (existing is null) { Nav.NavigateTo("patients"); return; }
            patient = existing;
            owner = existing.Owner;
            useExistingOwner = true;
        }
    }

    void OwnerSelected(ChangeEventArgs e)
    {
        if (int.TryParse(e.Value?.ToString(), out var oid))
        {
            var selected = owners?.FirstOrDefault(o => o.Id == oid);
            if (selected != null) { owner = selected; useExistingOwner = true; return; }
        }
        owner = new Owner();
        useExistingOwner = false;
    }

    async Task SaveAsync()
    {
        saving = true;
        error = null;
        try
        {
            if (!useExistingOwner || owner.Id == 0)
                owner = await Svc.SaveOwnerAsync(owner);

            patient.OwnerId = owner.Id;
            patient.Owner = null!;
            await Svc.SavePatientAsync(patient);
            Nav.NavigateTo("patients");
        }
        catch (Exception ex)
        {
            error = ex.InnerException?.Message ?? ex.Message;
            saving = false;
        }
    }
}

@page "/patients/{Id:int}/history"
@attribute [Authorize]
@rendermode InteractiveServer
@inject ClinicService Svc
@inject NavigationManager Nav
@using Microsoft.AspNetCore.Components.Authorization

<PageTitle>Medical History — @(patient?.Name ?? "Patient")</PageTitle>

@if (patient is null)
{
    <p><em>Loading...</em></p>
}
else
{
    <div class="d-flex justify-content-between align-items-center mb-3">
        <h1>📋 Medical History — @patient.Name</h1>
        <a href="patients/@Id" class="btn btn-outline-secondary">← Back to Patient</a>
    </div>

    <div class="row mb-4">
        <div class="col-md-4">
            <div class="card">
                <div class="card-body">
                    <p><strong>Species:</strong> @patient.Species</p>
                    <p><strong>Breed:</strong> @(patient.Breed ?? "N/A")</p>
                    <p><strong>DOB:</strong> @(patient.DateOfBirth?.ToString("MMM dd, yyyy") ?? "N/A")</p>
                    <p><strong>Weight:</strong> @(patient.WeightKg.HasValue ? $"{patient.WeightKg} kg" : "N/A")</p>
                    <p><strong>Owner:</strong> @patient.Owner.FullName</p>
                </div>
            </div>
        </div>
    </div>

    <h3>Treatment Notes</h3>

    <div class="card mb-3">
        <div class="card-header">
            <h5>@(editingNote?.Id > 0 ? "Edit Note" : "Add Treatment Note")</h5>
        </div>
        <div class="card-body">
            <EditForm Model="editingNote" OnValidSubmit="SaveNoteAsync" FormName="NoteForm">
                <DataAnnotationsValidator />
                <div class="row mb-2">
                    <div class="col-md-4">
                        <label class="form-label">Date</label>
                        <InputDate class="form-control" Type="InputDateType.DateTimeLocal" @bind-Value="editingNote!.Date" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Title *</label>
                        <InputText class="form-control" @bind-Value="editingNote.Title" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Recorded By</label>
                        <InputText class="form-control" @bind-Value="editingNote.RecordedBy" />
                    </div>
                </div>
                <div class="mb-2">
                    <label class="form-label">Description *</label>
                    <InputTextArea class="form-control" rows="3" @bind-Value="editingNote.Description" />
                </div>
                <div class="mb-2">
                    <label class="form-label">Medications</label>
                    <InputText class="form-control" @bind-Value="editingNote.Medications" />
                </div>
                <button type="submit" class="btn btn-primary me-2">Save Note</button>
                @if (editingNote.Id > 0)
                {
                    <button type="button" class="btn btn-secondary" @onclick="CancelEdit">Cancel</button>
                }
            </EditForm>
        </div>
    </div>

    @if (patient.TreatmentNotes.Count == 0)
    {
        <div class="alert alert-info">No treatment notes yet.</div>
    }
    else
    {
        @foreach (var note in patient.TreatmentNotes)
        {
            <div class="card mb-2">
                <div class="card-body">
                    <div class="d-flex justify-content-between">
                        <h5>@note.Title</h5>
                        <small class="text-muted">@note.Date.ToString("MMM dd, yyyy h:mm tt") — @(note.RecordedBy ?? "Staff")</small>
                    </div>
                    <p>@note.Description</p>
                    @if (!string.IsNullOrEmpty(note.Medications))
                    {
                        <p><strong>Medications:</strong> @note.Medications</p>
                    }
                    <button class="btn btn-sm btn-outline-primary me-1" @onclick="() => EditNote(note)">Edit</button>
                    <button class="btn btn-sm btn-outline-danger" @onclick="() => DeleteNoteAsync(note.Id)">Delete</button>
                </div>
            </div>
        }
    }
}

@code {
    [Parameter] public int Id { get; set; }

    Patient? patient;
    TreatmentNote? editingNote;

    protected override async Task OnInitializedAsync()
    {
        await LoadAsync();
        ResetNote();
    }

    async Task LoadAsync()
    {
        patient = await Svc.GetPatientAsync(Id);
        if (patient is null) Nav.NavigateTo("patients");
    }

    void ResetNote()
    {
        editingNote = new TreatmentNote { PatientId = Id, Date = DateTime.UtcNow };
    }

    void EditNote(TreatmentNote note)
    {
        editingNote = new TreatmentNote
        {
            Id = note.Id,
            PatientId = note.PatientId,
            Date = note.Date,
            Title = note.Title,
            Description = note.Description,
            Medications = note.Medications,
            RecordedBy = note.RecordedBy
        };
    }

    void CancelEdit() => ResetNote();

    async Task SaveNoteAsync()
    {
        await Svc.SaveTreatmentNoteAsync(editingNote!);
        await LoadAsync();
        ResetNote();
    }

    async Task DeleteNoteAsync(int id)
    {
        await Svc.DeleteTreatmentNoteAsync(id);
        await LoadAsync();
    }
}

