                            <a href="appointments/@a.Id" class="btn btn-sm btn-outline-primary me-1">Reschedule</a>
                            <button class="btn btn-sm btn-outline-warning me-1" @onclick="() => CompleteAsync(a)">Complete</button>
                            <button class="btn btn-sm btn-outline-danger" @onclick="() => CancelAsync(a.Id)">Cancel</button>
                        }
                        else
                        {
                            <a href="appointments/@a.Id" class="btn btn-sm btn-outline-secondary">View</a>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>
